import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testValueOf_withPredefinedFormats() {
        // Test known predefined formats by name
        assertSame(CSVFormat.DEFAULT, CSVFormat.valueOf("Default"));
        assertSame(CSVFormat.EXCEL, CSVFormat.valueOf("Excel"));
        assertSame(CSVFormat.INFORMIX_UNLOAD, CSVFormat.valueOf("InformixUnload"));
        assertSame(CSVFormat.INFORMIX_UNLOAD_CSV, CSVFormat.valueOf("InformixUnloadCsv"));
        assertSame(CSVFormat.MYSQL, CSVFormat.valueOf("MySQL"));
        assertSame(CSVFormat.POSTGRESQL_CSV, CSVFormat.valueOf("PostgreSQLCsv"));
        assertSame(CSVFormat.POSTGRESQL_TEXT, CSVFormat.valueOf("PostgreSQLText"));
        assertSame(CSVFormat.RFC4180, CSVFormat.valueOf("RFC4180"));
        assertSame(CSVFormat.TDF, CSVFormat.valueOf("TDF"));
    }

    @Test
    void testValueOf_caseInsensitive() {
        // Case insensitive check for predefined format names
        assertSame(CSVFormat.DEFAULT, CSVFormat.valueOf("default"));
        assertSame(CSVFormat.EXCEL, CSVFormat.valueOf("eXceL"));
    }

    @Test
    void testValueOf_invalidFormat_throwsIllegalArgumentException() {
        // Should throw IllegalArgumentException for unknown format
        assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf("unknownFormat"));
        assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf(""));
        assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf(null));
    }
}
